BEGIN TRANSACTION;
CREATE TABLE ads (
    library_id TEXT NOT NULL,
    run_id INTEGER NOT NULL,
    keyword TEXT,
    niche TEXT,
    page_name TEXT,
    brand TEXT,
    start_date TEXT,
    end_date TEXT,
    is_active INTEGER,
    days_running INTEGER,
    platforms TEXT,
    ad_text TEXT,
    landing_url TEXT,
    media_type TEXT,
    media_url TEXT,
    score REAL,
    variants_from_brand INTEGER,
    scraped_at TEXT, mp_source TEXT, mp_currency TEXT, mp_price REAL, mp_sold INTEGER, mp_rating REAL, mp_reviews INTEGER, mp_enriched_at TEXT, geo_signal TEXT, niche_relevance TEXT, score_normalized REAL, llm_hook_angle TEXT, llm_claim_type TEXT, llm_target_demo TEXT, llm_classified_at TEXT, category TEXT, sub_category TEXT, location TEXT,
    PRIMARY KEY (library_id, run_id),
    FOREIGN KEY (run_id) REFERENCES runs(run_id) ON DELETE CASCADE
);
CREATE TABLE bestsellers (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    platform TEXT NOT NULL,
    snapshot_date TEXT NOT NULL,
    niche TEXT,
    keyword TEXT,
    rank INTEGER,
    product_name TEXT,
    product_url TEXT,
    price_php REAL,
    units_sold INTEGER,
    rating REAL,
    review_count INTEGER,
    shop_name TEXT,
    thumbnail_url TEXT,
    captured_at TEXT NOT NULL
);
CREATE TABLE brand_meta (
    brand TEXT PRIMARY KEY,
    starred INTEGER DEFAULT 0,
    status TEXT DEFAULT '',
    notes TEXT DEFAULT '',
    created_at TEXT,
    updated_at TEXT
, competitor INTEGER DEFAULT 0);
CREATE TABLE creatives (
    library_id TEXT PRIMARY KEY,
    media_type TEXT,
    media_path TEXT,
    media_url TEXT,
    downloaded_at TEXT,
    file_size INTEGER
);
CREATE TABLE product_testing (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    date_added TEXT NOT NULL,
    product_name TEXT NOT NULL,
    brand_name TEXT,
    niche TEXT,
    pain_point TEXT,
    emotional_benefits TEXT,
    physical_effects TEXT,
    main_ingredients TEXT,
    target_age TEXT,
    target_gender TEXT,
    target_behavior TEXT,
    target_interest TEXT,
    target_demographics TEXT,
    status TEXT DEFAULT 'queued',
    notes TEXT,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
, hunted_by TEXT, launch_date TEXT, units_sold INTEGER, revenue_php REAL, ad_spend_php REAL, cogs_php REAL, roas REAL, net_profit_php REAL, outcome TEXT, learnings TEXT, launch_checklist TEXT, dti_permit_no TEXT, dti_expiry TEXT, fda_cpr_no TEXT, fda_expiry TEXT, bir_or_no TEXT);
CREATE TABLE runs (
    run_id INTEGER PRIMARY KEY AUTOINCREMENT,
    started_at TEXT NOT NULL,
    finished_at TEXT,
    niches TEXT,
    total_ads INTEGER DEFAULT 0,
    source TEXT DEFAULT 'scrape',
    notes TEXT
);
CREATE TABLE seller_snapshots (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    store_id INTEGER NOT NULL,
    snapshot_date TEXT NOT NULL,
    units_sold INTEGER,
    revenue_php REAL,
    rating REAL,
    review_count INTEGER,
    follower_count INTEGER,
    notes TEXT,
    FOREIGN KEY(store_id) REFERENCES seller_stores(id) ON DELETE CASCADE
);
CREATE TABLE seller_stores (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    platform TEXT NOT NULL,           -- 'shopee' | 'lazada' | 'tiktok_shop' | 'own_site'
    store_name TEXT NOT NULL,
    store_url TEXT,
    niche TEXT,
    notes TEXT,
    created_at TEXT NOT NULL
);
CREATE TABLE swipe_collections (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL,
    created_at TEXT NOT NULL
);
CREATE TABLE swipe_items (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    collection_id INTEGER NOT NULL,
    brand TEXT,
    niche TEXT,
    creative_path TEXT,
    landing_url TEXT,
    ad_text TEXT,
    notes TEXT,
    saved_at TEXT NOT NULL,
    FOREIGN KEY(collection_id) REFERENCES swipe_collections(id) ON DELETE CASCADE
);
CREATE TABLE tiktok_ads (
    ad_id TEXT NOT NULL,
    run_id INTEGER NOT NULL,
    captured_at TEXT,
    country TEXT,
    industry TEXT,
    advertiser TEXT,
    title TEXT,
    description TEXT,
    cta TEXT,
    likes INTEGER,
    comments INTEGER,
    shares INTEGER,
    plays INTEGER,
    ctr REAL,
    duration_seconds INTEGER,
    first_shown TEXT,
    last_shown TEXT,
    thumbnail_url TEXT,
    video_url TEXT,
    detail_url TEXT,
    raw_text TEXT,
    PRIMARY KEY (ad_id, run_id),
    FOREIGN KEY (run_id) REFERENCES runs(run_id) ON DELETE CASCADE
);
