CREATE INDEX idx_ads_library_id ON ads(library_id);
CREATE INDEX idx_ads_brand ON ads(brand);
CREATE INDEX idx_ads_niche ON ads(niche);
CREATE INDEX idx_ads_run_id ON ads(run_id);
CREATE INDEX idx_ads_is_active ON ads(is_active);
CREATE INDEX idx_tiktok_likes ON tiktok_ads(likes);
CREATE INDEX idx_tiktok_run ON tiktok_ads(run_id);
CREATE INDEX idx_brand_meta_starred ON brand_meta(starred);
CREATE INDEX idx_brand_meta_status ON brand_meta(status);
CREATE INDEX idx_testing_status ON product_testing(status);
CREATE INDEX idx_testing_date ON product_testing(date_added DESC);
CREATE INDEX idx_seller_snap_date ON seller_snapshots(snapshot_date DESC);
CREATE INDEX idx_bestsellers_date ON bestsellers(snapshot_date DESC);
CREATE INDEX idx_bestsellers_niche ON bestsellers(niche);
CREATE INDEX idx_bestsellers_platform ON bestsellers(platform);
CREATE INDEX idx_swipe_item_coll ON swipe_items(collection_id);
DELETE FROM "sqlite_sequence";
COMMIT;
