INSERT INTO "ads" VALUES('1649135352872077',1,'weight loss capsule','capsule','Wellness Insider','Wellness Insider','2026-05-06',NULL,1,6,NULL,'My brother Dean called me on a Sunday afternoon in April and said the words I''d been dreading for 6 months. "It''s time. Dad''s moving to Birchwood on the 19th. We have to clean out the garage." I sat on the couch in my living room in Erie and I looked out the window at my own garage and I felt the weight of 47 years settle on my chest. Our father had lived in the same house in Mentor, Ohio since 1978. The garage had been his cathedral. He''d built workbenches along three walls, hung pegboards above them, organized every screw and bolt and washer into glass baby food jars with the lids screwed to','https://www.facebook.com/61588061437549/','','',9.0,1,'2026-05-12T09:51:08',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'unknown','no_match',9.0,NULL,NULL,NULL,NULL,'Health & Wellness','slimming',NULL);
