INSERT INTO "ads" VALUES('1552676622495694',3,'hair oil','oil','The Tech Report PH','The Tech Report PH','2026-03-18',NULL,1,55,NULL,'Sand is typically described as fine particles. That description omits the one material property that matters when a phone is resting on a beach towel: hardness. Beach sand is primarily quartz — silicon dioxide crystals that measure 7 on the Mohs hardness scale. The iPhone aluminum frame measures 2.5. That gap of 4.5 points does not mean quartz scratches aluminum aggressively. It means quartz scratches aluminum at any contact angle, under any load — including the weight of sand settling against a phone resting on a beach towel. The Mohs scale is not linear in the way most people assume. A mater','https://fb.com/canvas_doc/939799531876651','','',107.5,6,'2026-05-12T10:08:59',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'unknown','no_match',107.5,NULL,NULL,NULL,NULL,'Beauty & Personal Care','whitening',NULL);
