INSERT INTO "ads" VALUES('1437425681195604',3,'hair oil','oil','The Tech Report PH','The Tech Report PH','2026-03-19',NULL,1,54,NULL,'There is one hardware spec in the Galaxy S26 Ultra that Samsung did not include in the marketing material. Every other number is documented — the Snapdragon 8 Elite Gen 5, the 200MP sensor, the 7.9mm profile. But the Mohs hardness rating of the frame is not in the spec sheet. Samsung calls the material "Armor Aluminum." What aluminum actually scores on the Mohs scale is a separate question. That number is 2.5 to 3. The Mohs scale measures scratch resistance from 1 (softest) to 10 (hardest, diamond). For context: Philippine peso coins: 3.5 Mohs House keys: 5.5 Mohs Zipper pulls: 5 Mohs Quartz d','https://fb.com/canvas_doc/2094038571374047','','',106.0,6,'2026-05-12T10:09:03',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'unknown','no_match',106.0,NULL,NULL,NULL,NULL,'Beauty & Personal Care','whitening',NULL);
