INSERT INTO "ads" VALUES('1279156851080383',3,'capsule','capsule','North Ridge Health Clinic','GLOW UP','2026-05-06',NULL,1,6,NULL,'I almost killed a family on Interstate 40 last Tuesday. I want to say that out loud because I have not said it out loud and I am 56 years old and I have been driving a truck for 31 years and I have never come close to what I came close to at 4:17 in the morning outside Little Rock. I was eastbound on I-40 hauling a load of paper products to a distribution center in Memphis. Standard run. I''d done it 200 times. I left Oklahoma City at 11 PM. I''d had a 6 hour break before that. I was not over my hours. I was not low on sleep on paper. Somewhere around mile marker 152 I zoned out. I don''t know ho','https://alevia.com/amla/33','','',59.0,353,'2026-05-12T09:56:08',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'non-ph','no_match',59.0,NULL,NULL,NULL,NULL,'Health & Wellness','slimming',NULL);
INSERT INTO "ads" VALUES('1315084077187369',3,'capsule','capsule','Cholesterol Support Group','GLOW UP','2026-05-06',NULL,1,6,NULL,'I have been going to the same dog park in Toledo for 6 years and on a Tuesday morning in May I sat next to a widow on a green metal bench and she changed the way I think about every pill in my medicine cabinet. I want to write this down before I lose the nerve. Because I''m 62 years old and I''m a man who does not write things on the internet, and what this woman told me sitting on that bench has been keeping me up at night, and I think there are other men out there in other towns sitting on other benches who need to hear it. My name is Tom. I retired from the post office in 2022 after 38 years.','https://alevia.com/amla/33','','',59.0,353,'2026-05-12T09:56:09',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'non-ph','match',59.0,NULL,NULL,NULL,NULL,'Health & Wellness','slimming',NULL);
