INSERT INTO "ads" VALUES('955272247276117',3,'vitamin capsule','capsule','FERN-C','FERN-C','2026-05-11',NULL,1,1,NULL,'Did you know? To get a full 500mg of Vitamin C, you''d have to eat about 7–8 medium oranges daily. Imagine eating all that daily—hirap, ‘di ba? Not to mention the acidity! Ascorbic Acid (FERN-C®) makes it simple. It contains sodium ascorbate, so together with proper diet and exercise, it provides the Vitamin C support you need in a non-acidic and tummy-friendly capsule. Feel the C, the gentle way para Everyday C-GURADO ka! ASC Reference S0029N042726F','https://shopee.ph/stada.ph?shopCollection=252955990#product_list?utm_source=shopee&utm_medium=cpas&utm_campaign=stada','','',1.5,1,'2026-05-12T09:59:39',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'ph-confident','match',1.5,NULL,NULL,NULL,NULL,'Health & Wellness','supplements','PH-wide');
